def solve(*args, **kwargs):
    # Enumerate failure modes for the problem of extending GET /api/v1/problems
    # to filter by arbitrary skill tags (case-insensitive, comma-separated or array),
    # composing with difficulty and limit, preserving stable sorting.
    failure_modes = [
        {
            "id": 1,
            "name": "Incorrect Tag Filtering Logic (Case Sensitivity and Parsing Errors)",
            "rationale": (
                "The API must handle tags in a case-insensitive manner and accept multiple input formats "
                "(comma-separated strings or arrays). Failure to normalize case or parse inputs correctly "
                "can lead to incomplete or incorrect filtering results, causing the UI to display wrong problem sets."
            ),
            "tests": [
                # Minimal test: input tags as comma-separated string, mixed case
                {
                    "input": {"tags": "dp,Graph"},
                    "expected_tags": ["dp", "graph"],
                },
                # Minimal test: input tags as array, mixed case
                {
                    "input": {"tags": ["DP", "graph"]},
                    "expected_tags": ["dp", "graph"],
                },
                # Compose with difficulty and limit
                {
                    "input": {"tags": "dp", "difficulty": "easy", "limit": 10},
                    "expected_tags": ["dp"],
                },
            ],
        },
        {
            "id": 2,
            "name": "Failure to Compose with Difficulty and Limit Filters",
            "rationale": (
                "Filtering by tags must not break existing difficulty and limit filters. "
                "The combined filters must be applied conjunctively and sorting must remain stable."
            ),
        },
        {
            "id": 3,
            "name": "Failure to Surface Normalized Tag Filters in Metadata",
            "rationale": (
                "The API response metadata must include the normalized tag filters used, "
                "to allow the UI to reflect the active filters accurately."
            ),
        },
    ]
    return failure_modes
